                {hasVehicleInfo && (
                  <>
                    <Text
                      type="paragraphXL"
                      color="BRAND_COMPLEMENT_01"
                      mb="xxxxs"
                      mt="xxxxs"
                    >
                      Tag
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {vehicleInfo}
                    </Text>
                    <Divider />
                  </>
                )}
                {hasPurchaseTypeLabel && (
                  <>
                    <Text
                      type="paragraphXL"
                      color="BRAND_COMPLEMENT_01"
                      mb="xxxxs"
                      mt="xxxxs"
                    >
                      Tipo de compra
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {purchaseTypeLabel}
                    </Text>
                  </>
                )}
              </>
            )}

            {additionalFields.map((field, index) => (
              <React.Fragment key={`field-${index}`}>
                <Divider />
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  {field.label}
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {field.value}
                </Text>
              </React.Fragment>
            ))}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={() => setShowModal(true)}
            />
          </Box>
        </Box>

      </ScrollView>

      {showModal && (
        <ReportProblemModal onClose={() => setShowModal(false)} />
      )}
    </Box>
  );
}

