        borderTopRightRadius: 16,
        borderWidth: 1,
        borderColor: '#e0e0e0',
      }}
    >
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mt="small"
        mb="smaller"
      >
