const VARIANTS_MAP: Record<string, PointsTransaction> = {
  'Voucher Disponível': MOCK_VOUCHER_AVAILABLE,
  'Voucher Usado': MOCK_VOUCHER_USED,
  'Voucher Expirado': MOCK_VOUCHER_EXPIRED,
