function buildProcessedData(transaction: PointsTransaction) {
  const gainType = getTransactionGainType(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const isMarketplace = !!transaction.marketplace;
  const marketplace = transaction.marketplace;

  const marketplaceValuePoints = marketplace?.valuePoints;
  const formattedPointsValue =
    marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
      ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
      : getFormattedPointsValue(transaction.amount, transaction.type);

  const marketplaceTitle = getMarketplaceTitle(transaction);
  const cardTitle = marketplaceTitle || transaction.description || '';
  const highlightText = getFormattedHighlightText(transaction.date, gainType, moment);

  let marketplaceContent: MarketplaceContentData | undefined;
  if (isMarketplace && marketplace) {
    const firstPayment = marketplace.payments?.[0];
    const firstOrder = marketplace.orders?.[0];
    const vendorName = firstOrder?.vendor || '';

    const items: MarketplaceItemData[] = [];
    marketplace.orders?.forEach(order => {
      order.items?.forEach(item => {
        items.push({
          name: item.name,
          quantity: item.quantity,
          valuePoints: getFormattedPointsValueForMarketplace(item.valuePoints),
          imageUrl: item.imageUrl,
        });
      });
    });

    marketplaceContent = {
      orderNumber: transaction.id,
      status: transaction.status,
      statusColor: transaction.status
        ? STATUS_COLORS[transaction.status] || 'neutral'
        : undefined,
      paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
      shippingValuePoints:
        marketplace.shippingValuePoints !== undefined && marketplace.shippingValuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
          : undefined,
      valuePoints:
        marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
          : undefined,
      vendorName: vendorName || undefined,
      items,
    };
  }

  return {
    cardTitle,
    formattedPointsValue,
    highlightText,
    formattedCurrencyValue,
    marketplaceContent,
    showOrderNumber: !isMarketplace,
    showStatus: !isMarketplace,
    showValue: !isMarketplace,
  };
}

function OrderDetailsWrapper({
  variant = 'Voucher Disponível',
  isLoading = false,
  hasError = false,
}: {
  variant?: string;
  isLoading?: boolean;
  hasError?: boolean;
}) {
  const [showReportModal, setShowReportModal] = useState(false);
  const [showInfoModal, setShowInfoModal] = useState(false);
  const transaction = VARIANTS_MAP[variant] || MOCK_VOUCHER_AVAILABLE;
  const isCashback = variant === 'Cashback (Fatura)';

