        <Box flex={1} justify="center" align="center" minHeight={400}>
          <ActivityIndicator size="large" color={theme.colors.BRAND_BASE_01} />
        </Box>
      </Box>
    );
  }

  const data = buildProcessedData(transaction);
  const additionalFields = getAdditionalFields(transaction);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1} style={{ position: 'relative' }}>
