      statusColor: transaction.status
        ? STATUS_COLORS[transaction.status] || 'neutral'
        : undefined,
      paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
      shippingValuePoints:
        marketplace.shippingValuePoints !== undefined && marketplace.shippingValuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
          : undefined,
      valuePoints:
        marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
          ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
          : undefined,
      vendorName: vendorName || undefined,
      items,
    };
  }

  return {
    cardTitle,
    formattedPointsValue,
    highlightText,
    formattedCurrencyValue,
    marketplaceContent,
    showOrderNumber: !isMarketplace,
    showStatus: !isMarketplace,
    showValue: !isMarketplace,
  };
}

function OrderDetailsWrapper({
  variant = 'Voucher Disponível',
  isLoading = false,
  hasError = false,
}: {
  variant?: string;
  isLoading?: boolean;
  hasError?: boolean;
}) {
  const [showReportModal, setShowReportModal] = useState(false);
  const [showInfoModal, setShowInfoModal] = useState(false);
  const transaction = VARIANTS_MAP[variant] || MOCK_VOUCHER_AVAILABLE;
  const isCashback = transaction.type === 'RESCUE' && !transaction.marketplace;

  if (hasError) {
    return (
      <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
        <Header
          title="Detalhes do pedido"
          iconLeft="icon-back"
          hideLeftIcon={false}
          onBack={() => {}}
        />
        <Box flex={1} justify="center" align="center" pd="innerSmall">
          <Icon name="icon-alert" size={48} color={theme.colors.INTENSE_COLOR_01} />
          <Text type="headingMDL" color="BRAND_COMPLEMENT_01" mt="xs" align="center">
            Algo deu errado!
          </Text>
          <Text type="paragraphMD" color="INTENSE_COLOR_04" mt="xxxxs" align="center">
            Por favor, tente de novo.
          </Text>
          <Box mt="xs" width="100%">
            <Button text="Tentar novamente" onPress={() => {}} />
          </Box>
        </Box>
      </Box>
    );
  }

  if (isLoading) {
    return (
      <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
        <Header
          title="Detalhes do pedido"
          iconLeft="icon-back"
          hideLeftIcon={false}
          onBack={() => {}}
        />
        <Box flex={1} justify="center" align="center" minHeight={400}>
          <ActivityIndicator size="large" color={theme.colors.BRAND_BASE_01} />
        </Box>
      </Box>
    );
  }

  const data = buildProcessedData(transaction);
  const additionalFields = getAdditionalFields(transaction);

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1} style={{ position: 'relative' }}>
      <Header
        title="Detalhes do pedido"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        rightIcon={isCashback ? 'icon-help' : undefined}
        hideRightIcon={!isCashback}
        onPressRightIcon={() => setShowInfoModal(true)}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={data.cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={data.formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? 'PLUS_COLOR_02'
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={data.highlightText}
            showSpacing
            mb="xs"
          />

          <Box flex={1} width="100%">
            {data.showOrderNumber && (
              <>
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
                  Número do pedido
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  #{transaction.id}
                </Text>
              </>
            )}

            {data.showStatus && transaction.status && (
              <>
                <Divider />
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  Status do pedido
                </Text>
                <TagLabel
                  type={STATUS_COLORS[transaction.status] || 'neutral'}
                  text={transaction.status}
                  showSpacing
                />
              </>
            )}

            {data.showValue && (
              <>
                <Divider />
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  Valor
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {data.formattedCurrencyValue}
                </Text>
              </>
            )}

            {!data.marketplaceContent && additionalFields.map((field, index) => (
              <React.Fragment key={`${field.label}-${index}`}>
                <Divider />
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  {field.label}
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {field.value}
                </Text>
              </React.Fragment>
            ))}

            {data.marketplaceContent && (
              <>
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                  Número do pedido
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  #{data.marketplaceContent.orderNumber}
                </Text>

                {data.marketplaceContent.status && (
                  <>
                    <Divider />
                    <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                      Status do pedido
                    </Text>
                    <TagLabel
                      type={(data.marketplaceContent.statusColor as never) || 'neutral'}
                      text={data.marketplaceContent.status}
                      showSpacing
                    />
                  </>
                )}

                {data.marketplaceContent.paymentType && (
                  <>
                    <Divider />
                    <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                      Forma de pagamento
                    </Text>
                    <Text type="paragraphMD" color="INTENSE_COLOR_03">
                      {data.marketplaceContent.paymentType}
                    </Text>
                  </>
                )}

                {data.marketplaceContent.shippingValuePoints !== undefined &&
                  data.marketplaceContent.shippingValuePoints !== null && (
                    <>
                      <Divider />
                      <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                        Frete
                      </Text>
                      <Text type="paragraphMD" color="INTENSE_COLOR_03">
                        {data.marketplaceContent.shippingValuePoints}
                      </Text>
                    </>
                  )}

                {data.marketplaceContent.valuePoints !== undefined &&
                  data.marketplaceContent.valuePoints !== null && (
                    <>
                      <Divider />
                      <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                        Valor total
                      </Text>
                      <Text type="paragraphMD" color="INTENSE_COLOR_03">
                        {data.marketplaceContent.valuePoints}
                      </Text>
                    </>
                  )}

                {data.marketplaceContent.vendorName && (
                  <>
                    <Divider />
                    <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
                      Parceiro: {data.marketplaceContent.vendorName}
                    </Text>
                  </>
                )}

                {data.marketplaceContent.items.map((item, idx) => (
                  <CardActivity
                    key={idx}
                    mt="nano"
                    title={item.name}
                    titleTextType="paragraphMD"
                    description={`Quantidade: ${item.quantity}\nValor: ${item.valuePoints}`}
                    descriptionTextType="paragraphSM"
                    showImage={false}
                    showIcon={false}
                    iconRight={null as never}
                    hideBorder={false}
                  />
                ))}

                <Alert
                  title="Detalhes da entrega"
                  mt="meddium"
                  label="Você pode acompanhar a entrega do seu pedido pelo site do parceiro."
                  numberOfLines={2}
                  type="highlight"
                  icon="icon-truck"
                  hasIconBackground
                  bgIconColor="BRAND_COMPLEMENT_03"
                />
              </>
            )}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="ghostLarge"
              text="Relatar Problema"
              onPress={() => setShowReportModal(true)}
            />
          </Box>
        </Box>
      </ScrollView>

      {showReportModal && <ReportProblemModal onClose={() => setShowReportModal(false)} />}
      {showInfoModal && <InfoModal onClose={() => setShowInfoModal(false)} />}
    </Box>
  );
}

const meta: Meta<typeof OrderDetailsWrapper> = {
  title: 'Screens/MyOrdersDetails',
  component: OrderDetailsWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    variant: {
      control: { type: 'select' },
      options: Object.keys(VARIANTS_MAP),
      description: 'Order detail variant to display',
    },
    isLoading: {
      control: 'boolean',
      description: 'Show loading state',
    },
    hasError: {
      control: 'boolean',
      description: 'Show error state',
    },
  },
};

export default meta;
type Story = StoryObj<typeof OrderDetailsWrapper>;

export const VoucherAvailable: Story = {
  name: 'Voucher Disponível',
  args: { variant: 'Voucher Disponível' },
};

export const VoucherUsed: Story = {
  name: 'Voucher Usado (Finalizado)',
  args: { variant: 'Voucher Usado' },
};

export const VoucherExpired: Story = {
  name: 'Voucher Expirado (Cancelado)',
  args: { variant: 'Voucher Expirado' },
};

export const CashbackOrder: Story = {
  name: 'Cashback (Fatura)',
  args: { variant: 'Cashback (Fatura)' },
};

export const MarketplaceOrder: Story = {
  name: 'Marketplace Order',
  args: { variant: 'Marketplace Order' },
};

export const LoadingState: Story = {
  name: 'Loading State',
  args: { isLoading: true },
};

export const ErrorState: Story = {
  name: 'Error State',
  args: { hasError: true },
};

